const email = $input.first().json;
const subject = email.subject || '(no subject)';
const message = email.textPlain || email.snippet || '';
const from = email.from?.value?.[0]?.address || email.from || '';
return [{ json: { external_ticket_id: email.id || $execution.id, customer_email: from, subject, message, priority: /urgent|blocked|production/i.test(subject + ' ' + message) ? 'high' : 'normal', channel: 'gmail' } }];

const ticket = $('Code - Normalize Gmail Message To Ticket').first().json;
const raw = $input.first().json;
const content = raw.choices?.[0]?.message?.content || '{}';
let parsed;
try { parsed = typeof content === 'string' ? JSON.parse(content) : content; } catch (error) { parsed = { category: 'Other', confidence: 0, drafted_reply: 'Manual review required.', risk_flags: ['llm_parse_error'], route: 'escalation' }; }
const risky = (parsed.risk_flags || []).length > 0 || Number(parsed.confidence || 0) < 0.7;
const route = risky || parsed.route === 'escalation' ? 'escalation' : 'approval';
return [{ json: { ...ticket, category: parsed.category || 'Other', confidence: Number(parsed.confidence || 0), matched_article_title: parsed.matched_article_title || '', drafted_reply: parsed.drafted_reply || 'Manual review required.', risk_flags: parsed.risk_flags || [], route, model_name: $env.OPENROUTER_MODEL, prompt_version: 'support_triage_v1' } }];
